const staleJobs = Number($json.stale_jobs_recovered || 0);
const staleItems = Number($json.stale_items_recovered || 0);
const cancelled = Number($json.jobs_cancelled || 0);
if (!cancelled || !$json.alert_chat_id) return [];
return [{ json: {
  chat_id: $json.alert_chat_id,
  text: `⚠️ Inbox Agent: ${cancelled} job(s) зупинено після вичерпання повторних спроб. Відновлено stale jobs: ${staleJobs}, stale items: ${staleItems}.`
} }];
